@@ -1,0 +1,93 @@
+<div class="catalog-filters">
+    <h4>Filters</h4>
+
+    <div class="filter-section">
+        <h5>Categories</h5>
+        @if (Categories is null)
+        {
+            <p class="filter-loading">Loading…</p>
+        }
+        else
+        {
+            @foreach (var category in Categories)
+            {
+                <label class="filter-checkbox">
+                    <input type="checkbox"
+                           checked="@selectedCategories.Contains(category)"
+                           @onchange="() => ToggleCategory(category)" />
+                    @category
+                </label>
+            }
+        }
+    </div>
+
+    <div class="filter-section">
+        <h5>Price Range</h5>
+        <div class="price-inputs">
+            <input type="number" placeholder="Min" min="0" step="0.01"
+                   value="@minPrice" @onchange="e => minPrice = ParseDecimal(e.Value)" />
+            <span>–</span>
+            <input type="number" placeholder="Max" min="0" step="0.01"
+                   value="@maxPrice" @onchange="e => maxPrice = ParseDecimal(e.Value)" />
+        </div>
+    </div>
+
+    <div class="filter-section">
+        <label class="filter-checkbox">
+            <input type="checkbox" checked="@inStockOnly"
+                   @onchange="e => inStockOnly = (bool)(e.Value ?? false)" />
+            In Stock Only
+        </label>
+    </div>
+
+    <div class="filter-actions">
+        <button class="btn-apply" @onclick="ApplyFilters">Apply Filters</button>
+        <button class="btn-clear" @onclick="ClearFilters">Clear Filters</button>
+    </div>
+</div>
+
+@code {
+    [Parameter] public IReadOnlyList<string>? Categories { get; set; }
+    [Parameter] public EventCallback<ProductFilter> OnFilterApplied { get; set; }
+
+    private HashSet<string> selectedCategories = [];
+    private decimal? minPrice;
+    private decimal? maxPrice;
+    private bool inStockOnly;
+
+    private void ToggleCategory(string category)
+    {
+        if (!selectedCategories.Remove(category))
+        {
+            selectedCategories.Add(category);
+        }
+    }
+
+    private async Task ApplyFilters()
+    {
+        var filter = new ProductFilter(
+            Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
+            MinPrice: minPrice,
+            MaxPrice: maxPrice,
+            InStockOnly: inStockOnly
+        );
+        await OnFilterApplied.InvokeAsync(filter);
+    }
+
+    private async Task ClearFilters()
+    {
+        selectedCategories = [];
+        minPrice = null;
+        maxPrice = null;
+        inStockOnly = false;
+        await OnFilterApplied.InvokeAsync(new ProductFilter(null, null, null, false));
+    }
+
+    private static decimal? ParseDecimal(object? value)
+    {
+        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
+            return null;
+        return decimal.TryParse(value.ToString(), out var result) ? result : null;
+    }
+}
+

