toolArgs.file_text:
@if (TotalPages > 1)
{
    <nav class="catalog-pagination">
        <button class="page-btn" disabled="@(Page <= 1)" @onclick="() => GoToPage(Page - 1)">
            Previous
        </button>

        @foreach (var p in GetPageNumbers())
        {
            <button class="page-btn @(p == Page ? "active" : "")"
                    @onclick="() => GoToPage(p)">
                @p
            </button>
        }

        <button class="page-btn" disabled="@(Page >= TotalPages)" @onclick="() => GoToPage(Page + 1)">
            Next
        </button>
    </nav>
}

@code {
    [Parameter] public int Page { get; set; }
    [Parameter] public int TotalPages { get; set; }
    [Parameter] public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page) => await OnPageChanged.InvokeAsync(page);

    private List<int> GetPageNumbers()
    {
        const int maxVisible = 5;
        var start = Math.Max(1, Page - maxVisible / 2);
        var end = Math.Min(TotalPages, start + maxVisible - 1);
        start = Math.Max(1, end - maxVisible + 1);

        var pages = new List<int>();
        for (var i = start; i <= end; i++)
            pages.Add(i);
        return pages;
    }
}

