arguments.file_text:
@page "/catalog"
@using sv_bd7cee4273cc4a5488aa30b23ab0995c.Components.Catalog
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1>Product Catalog</h1>

<div class="catalog-layout">
    <aside class="catalog-sidebar">
        <CatalogFilters Categories="@categories" OnFilterApplied="HandleFilterApplied" />
    </aside>

    <main class="catalog-main">
        @if (errorMessage is not null)
        {
            <div class="catalog-error">
                <p>@errorMessage</p>
                <button @onclick="RetryLoad">Retry</button>
            </div>
        }
        else if (isLoading)
        {
            <p class="catalog-loading">Loading products…</p>
        }
        else if (result is null || result.Items.Count == 0)
        {
            <p class="catalog-empty">No products found. Try adjusting your filters.</p>
        }
        else
        {
            <CatalogToolbar SortBy="@sortBy"
                            TotalCount="result.TotalCount"
                            Page="result.Page"
                            PageSize="result.PageSize"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="result.Items"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            <CatalogPagination Page="currentPage"
                               TotalPages="@totalPages"
                               OnPageChanged="HandlePageChanged" />
        }
    </main>
</div>

@code {
    [Parameter] public EventCallback<Product> OnProductSelected { get; set; }

    private const int PageSize = 12;
    private CancellationTokenSource cts = new();
    private List<string>? categories;
    private PagedResult<Product>? result;
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private bool isLoading = true;
    private string? errorMessage;
    private int totalPages => result is null || result.PageSize == 0
        ? 0
        : (int)Math.Ceiling((double)result.TotalCount / result.PageSize);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            categories = await ProductService.GetCategoriesAsync();
            await SearchProducts();
        }
        catch (OperationCanceledException) { }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load products: {ex.Message}";
            isLoading = false;
        }
    }

    private async Task SearchProducts()
    {
        isLoading = true;
        errorMessage = null;
        StateHasChanged();

        try
        {
            result = await ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);
        }
        catch (OperationCanceledException) { }
        catch (Exception ex)
        {
            errorMessage = $"Search failed: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await SearchProducts();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await SearchProducts();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await SearchProducts();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for cart integration
        return Task.CompletedTask;
    }

    private async Task RetryLoad()
    {
        errorMessage = null;
        currentPage = 1;
        await SearchProducts();
    }

    public ValueTask DisposeAsync()
    {
        cts.Cancel();
        cts.Dispose();
        return ValueTask.CompletedTask;
    }
}

.catalog-layout {
    display: flex;
    gap: 2rem;
    align-items: flex-start;
}

.catalog-sidebar {
    flex: 0 0 25%;
    min-width: 220px;
}

.catalog-main {
    flex: 1;
    min-width: 0;
}

.catalog-loading,
.catalog-empty {
    text-align: center;
    padding: 3rem 1rem;
    color: #6c757d;
    font-size: 1.1rem;
}

.catalog-error {
    text-align: center;
    padding: 2rem;
    background: #f8d7da;
    border: 1px solid #f5c2c7;
    border-radius: 8px;
    color: #842029;
}

.catalog-error button {
    margin-top: 1rem;
    padding: 0.5rem 1.5rem;
    border: none;
    border-radius: 6px;
    background: #dc3545;
    color: #fff;
    font-weight: 600;
    cursor: pointer;
}

.catalog-error button:hover {
    background: #bb2d3b;
}

